    input   [WIDTH-1:0] B;
    output  [WIDTH-1:0] SUM;
    output              CO;
    wire    [WIDTH:0]   obf_tmp;

    assign obf_tmp = A + B;
    assign SUM = obf_tmp [WIDTH-1:0];
    assign CO  = obf_tmp [WIDTH];

endmodule
